import jwt
from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Set secret key for HS256 algorithm
secret_key = "your_secret_key_here"

# Set public key for RS256 algorithm (PEM format)
public_key = """
-----BEGIN PUBLIC KEY-----
MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEAyJ6Zz1bD7l5nV4T2dW
...
-----END PUBLIC KEY-----
"""

def verify_token(token, algorithm):
    try:
        payload = jwt.decode(token, key=secret_key if algorithm == "HS256" else public_key, algorithms=[algorithm])
        return payload
    except jwt.ExpiredSignatureError:
        return {"error": "Token has expired"}
    except jwt.InvalidTokenError as e:
        return {"error": str(e)}

def authenticate(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get("Authorization")
        if not token:
            return jsonify({"error": "Missing Authorization header"}), 401
        payload = verify_token(token.split()[1], algorithm="HS256" if token.startswith("Bearer") else "RS256")
        if isinstance(payload, dict) and "error" in payload:
            return jsonify(payload), 401
        return f(*args, **kwargs)
    return decorated_function

@app.route("/protected", methods=["GET"])
@authenticate
def protected():
    return jsonify({"message": "Hello from a protected endpoint!"})

if __name__ == "__main__":
    app.run(debug=True)